column.value:
{
  "pageDescription": "Sample Creation & Full Metadata Capture",
  "entryModes": ["Individual Sample Entry", "Bulk Import (CSV/Manifest)"],
  "dataPoints": {
    "sampleIdentification": {
      "uniqueSampleId": {"type": "system", "label": "Unique Sample ID", "required": true, "autoGenerated": true, "description": "System-generated unique identifier"},
      "sampleName": {"type": "text", "label": "Sample Name", "required": true, "maxLength": 200},
      "alphanumericCode": {"type": "text", "label": "Alphanumeric Code", "required": false, "pattern": "^[A-Za-z0-9-]+$", "description": "External reference code"},
      "barcodeQrCode": {"type": "system", "label": "Barcode/QR Code", "required": true, "autoGenerated": true, "description": "System-generated scannable identifier"}
    },
    "chemistryMetadata": {
      "chemicalIupacName": {"type": "text", "label": "Chemical/IUPAC Name", "required": false, "maxLength": 500},
      "gradeSpecification": {"type": "text", "label": "Grade/Specification", "required": false, "description": "e.g., USP, BP, IP, Ph.Eur."}
    },
    "batchTraceability": {
      "lotBatchNumber": {"type": "text", "label": "Lot/Batch Number", "required": true, "maxLength": 100},
      "dateOfManufacture": {"type": "date", "label": "Date of Manufacture", "required": true, "format": "YYYY-MM-DD"},
      "expiryRetestDate": {"type": "date", "label": "Expiry/Re-test Date", "required": true, "format": "YYYY-MM-DD"}
    },
    "storageHandling": {
      "storageCondition": {"type": "choice", "label": "Storage Condition", "required": true, "options": ["Controlled Room Temp (15-25C)", "Refrigerated (2-8C)", "Frozen (-20C)", "Deep Frozen (-80C)", "Liquid Nitrogen", "Ambient", "Other"]}
    },
    "ownershipCustody": {
      "ownerRequester": {"type": "text", "label": "Owner/Requester", "required": true},
      "chainOfCustodyDetails": {"type": "textarea", "label": "Chain of Custody Details", "required": false}
    },
    "clinicalTrialMetadata": {
      "patientId": {"type": "text", "label": "Patient ID", "required": false, "description": "For clinical samples"},
      "clinicalTrialNumber": {"type": "text", "label": "Clinical Trial Number", "required": false},
      "consentStatus": {"type": "choice", "label": "Consent Status", "required": false, "options": ["Obtained", "Pending", "Waived", "Not Applicable"]}
    }
  },
  "bulkImportConfig": {
    "supportedFormats": ["CSV", "XLSX"],
    "maxRecordsPerImport": 1000,
    "requiredColumns": ["sampleName", "lotBatchNumber", "dateOfManufacture", "expiryRetestDate", "storageCondition", "ownerRequester"],
    "optionalColumns": ["alphanumericCode", "chemicalIupacName", "gradeSpecification", "chainOfCustodyDetails", "patientId", "clinicalTrialNumber", "consentStatus"],
    "autoGeneratedColumns": ["uniqueSampleId", "barcodeQrCode"]
  },
  "systemActions": ["Create sample record", "Generate unique sample ID", "Generate barcode/QR label", "Initialize chain of custody", "Set status: Created - Pending QC"],
  "nextPage": "Raw Sample Quality Check (QC)"
}
